def reachable_count(graph: dict[str, list[str]], start: str) -> int {
    seen = {};
    stack = [start];
    count = 0;
    while len(stack) > 0 {
        node_name = stack.pop();
        if node_name not in seen {
            seen[node_name] = True;
            count = count + 1;
            for next_name in graph[node_name] {
                if next_name not in seen {
                    stack.append(next_name);
                }
            }
        }
    }
    return count;
}

