def preorder_values(tree: dict[str, list[str]], start: str) -> list[str] {
    order = [];
    stack = [start];
    while len(stack) > 0 {
        current = stack.pop();
        order.append(current);
        children = tree[current];
        idx = len(children) - 1;
        while idx >= 0 {
            stack.append(children[idx]);
            idx = idx - 1;
        }
    }
    return order;
}

