def process_until_stop(events: list[str]) -> list[str] {
    processed = [];
    idx = 0;
    while idx < len(events) {
        event = events[idx];
        if event == "stop" {
            return processed;
        }
        processed.append(event);
        idx = idx + 1;
    }
    return processed;
}

